new="""  function selectedText(el, emptyLabel){ return (el && el.selectedIndex > 0) ? esc(el.options[el.selectedIndex].text) : emptyLabel; }\n  function setHeroMetric(base, strongText, smallText){ const strong=root.querySelector('#'+base); const note=root.querySelector('#'+base+'-note'); if(strong && strongText != null) strong.textContent=String(strongText); if(note && smallText != null) note.textContent=String(smallText); }\n  function fmtKm(v){ const n=parseFloat(v||0)||0; return n>0 ? n.toLocaleString('pt-PT',{maximumFractionDigits:1})+' km' : '0 km'; }\n  function routeStops(r){ return parseInt(r?.stops_count ?? r?.stops ?? 0,10)||0; }\n  function routeDone(r){ return parseInt(r?.stops_done ?? r?.done_stops ?? 0,10)||0; }\n  function routeKm(r){ if(!r) return 0; if(r.distance_km!=null && r.distance_km!=='') return parseFloat(r.distance_km)||0; const meta=typeof r.meta_json==='string' ? (()=>{try{return JSON.parse(r.meta_json)||{};}catch(_){return {};}})() : (r.meta_json||{}); const buckets=[meta.route_metrics||{},meta.plan_summary||{},meta.metrics||{},meta||{}]; for(const b of buckets){ if(b && b.distance_km!=null && !isNaN(parseFloat(b.distance_km))) return parseFloat(b.distance_km)||0; if(b && b.total_distance_km!=null && !isNaN(parseFloat(b.total_distance_km))) return parseFloat(b.total_distance_km)||0; } return 0; }\n  function routeOwner(r){ return r?.owner_name || r?.user_name || selectedText(els.owner,'Operativo'); }\n  function routeProject(r){ return r?.project_name || selectedText(els.project,'Campanha'); }\n  function dateRange(from,to){ const out=[]; if(!from||!to) return out; const d=new Date(from+'T00:00:00'); const end=new Date(to+'T00:00:00'); while(d<=end){ out.push(d.toISOString().slice(0,10)); d.setDate(d.getDate()+1); } return out; }\n  function agendaRange(){ const from=(els.from&&els.from.value)||new Date().toISOString().slice(0,10); const to=(els.to&&els.to.value)||from; const startYear=parseInt(String(from).slice(0,4),10)||new Date().getFullYear(); const endYear=parseInt(String(to).slice(0,4),10)||startYear; if(els.owner&&els.owner.value){ return {from:startYear+'-01-01', to:endYear+'-12-31', label:'Agenda anual'}; } return {from:from, to:to, label:'Período'}; }\n  function paramsForRouteAgenda(){ const p=new URLSearchParams(); const range=agendaRange(); p.set('date_from',range.from); p.set('date_to',range.to); p.set('limit','1000'); if(els.client&&els.client.value) p.set('client_id',els.client.value); if(els.project&&els.project.value) p.set('project_id',els.project.value); if(els.owner&&els.owner.value) p.set('owner_user_id',els.owner.value); if(!(els.owner&&els.owner.value) && els.location&&els.location.value) p.set('location_id',els.location.value); return {params:p, range}; }\n  function switchPanel(key){ root.querySelectorAll('.rp-tabbar button').forEach(b=>b.classList.toggle('active',(b.dataset.panel||'overview')===key)); root.querySelectorAll('.rp-panel').forEach(panel=>panel.classList.toggle('active',panel.dataset.panel===key)); const target=root.querySelector('.rp-panel[data-panel="'+key+'"]'); if(target){ ensurePortalTableScroll(); setTimeout(()=>target.scrollIntoView({behavior:'smooth',block:'start'}),10); target.querySelectorAll('.rp-front-commercial,.rp-front-routes,.routespro-dashboard').forEach(el=>el.dispatchEvent(new CustomEvent('routespro:panel-open',{detail:{panel:key}}))); } }\n  function setRouteDateLock(date, routeId){ state.routeDateLocked=!!date; state.lockedDate=date||''; if(els.from){ els.from.disabled=!!date; if(date) els.from.value=date; } if(els.to){ els.to.disabled=!!date; if(date) els.to.value=date; } if(els.routeLock){ els.routeLock.classList.toggle('active',!!date); const span=els.routeLock.querySelector('span'); if(span) span.textContent=date ? `Filtro de data bloqueado pela rota #${routeId||state.selectedRouteId||''}, ${date}.` : 'Filtro de data desbloqueado.'; } }\n  function renderOwnerRoutesSummary(){ if(!els.ownerRoutesSummary) return; const routes=Array.isArray(state.routeAgenda)?state.routeAgenda:[]; if(!els.owner||!els.owner.value){ els.ownerRoutesSummary.innerHTML='<div class="rp-panel-head" style="margin-bottom:8px"><div><h4 style="margin:0">Rotas atribuídas ao operativo</h4><p>Escolhe um operativo para ver a agenda de rotas já criadas, mesmo fora do filtro de data atual.</p></div><span class="rp-pill">Agenda</span></div><div class="rp-chart-empty">Seleciona um operativo para carregar a respetiva agenda de rotas.</div>'; return; } const totalKm=routes.reduce((n,r)=>n+routeKm(r),0); const totalStops=routes.reduce((n,r)=>n+routeStops(r),0); const range=state.routeAgendaRange||agendaRange(); const next=routes.slice().sort((a,b)=>String(a.date||'').localeCompare(String(b.date||'')) || (parseInt(a.id||0,10)-parseInt(b.id||0,10))).slice(0,8); const list=next.map(r=>`<button type="button" class="rp-route-summary-item ${String(r.id)===String(state.selectedRouteId)?'active':''}" data-open-route="${esc(r.id)}"><strong>${esc(r.date||'')}</strong><span><b>Rota #${esc(r.id)}</b><br><small>${esc(routeProject(r))} · ${esc(routeOwner(r))} · ${routeStops(r)} PDVs</small></span><span>${fmtKm(routeKm(r))}</span></button>`).join(''); els.ownerRoutesSummary.innerHTML=`<div class="rp-panel-head" style="margin-bottom:8px"><div><h4 style="margin:0">Rotas atribuídas ao operativo</h4><p>${esc(selectedText(els.owner,'Operativo'))} · ${esc(range.from)} a ${esc(range.to)} · independente do filtro diário atual.</p></div><span class="rp-pill">${routes.length} rotas</span></div><div class="rp-kpi-grid">${metric('Rotas atribuídas',routes.length,'Agenda carregada do operativo')}${metric('PDVs em rota',totalStops,'Paragens planeadas')}${metric('Kms estimados',fmtKm(totalKm),'Total das rotas visíveis')}${metric('Próximas rotas',next.length,'Clique para abrir em Rotas')}</div><div class="rp-route-summary-list">${list||'<div class="rp-chart-empty">Sem rotas criadas para este operativo no intervalo anual.</div>'}</div>`; els.ownerRoutesSummary.querySelectorAll('[data-open-route]').forEach(btn=>btn.addEventListener('click',()=>openRouteFromAgenda(btn.dataset.openRoute))); }\n  function renderRouteCalendar(){ if(!els.routeCalendar) return; const routes=Array.isArray(state.routes)?state.routes:[]; const range=state.routeAgendaRange||agendaRange(); if(els.routeAgendaLabel) els.routeAgendaLabel.textContent=(els.owner&&els.owner.value)?'Agenda anual':'Período'; if(!routes.length){ els.routeCalendar.innerHTML='<div class="rp-chart-empty" style="grid-column:1/-1">Sem rotas para mostrar em calendário.</div>'; return; } const groups=new Map(); routes.slice().sort((a,b)=>String(a.date||'').localeCompare(String(b.date||''))).forEach(r=>{ const key=String(r.date||'').slice(0,7)||'Sem data'; if(!groups.has(key)) groups.set(key,[]); groups.get(key).push(r); }); const html=Array.from(groups.entries()).map(([month,items])=>{ const chips=items.map(r=>{ const day=String(r.date||'').slice(8,10)||'?'; return `<button type="button" class="rp-day-chip ${String(r.id)===String(state.selectedRouteId)?'active':''}" data-open-route="${esc(r.id)}"><span>${esc(day)}</span><small>#${esc(r.id)} · ${fmtKm(routeKm(r))}<br>${routeStops(r)} PDVs</small></button>`; }).join(''); return `<div class="rp-month-card"><h5>${esc(month)} · ${items.length} rota${items.length===1?'':'s'}</h5><div class="rp-month-days">${chips}</div></div>`; }).join(''); els.routeCalendar.innerHTML=html; els.routeCalendar.querySelectorAll('[data-open-route]').forEach(btn=>btn.addEventListener('click',()=>openRouteFromAgenda(btn.dataset.openRoute))); }\n  async function openRouteFromAgenda(routeId){ const r=(state.routeAgenda||state.routes||[]).find(x=>String(x.id)===String(routeId)) || (state.routes||[]).find(x=>String(x.id)===String(routeId)); if(r&&r.date) setRouteDateLock(String(r.date), r.id); switchPanel('routes'); await selectRoute(routeId,true,false); }\n  async function loadRoutesRange(){ const cfg=paramsForRouteAgenda(); state.routeAgendaRange=cfg.range; const data=await j(api+'routes?'+cfg.params.toString()).catch(()=>({routes:[]})); const routes=(Array.isArray(data.routes)?data.routes:[]).sort((a,b)=> String(a.date||'').localeCompare(String(b.date||'')) || (parseInt(a.id||0,10)-parseInt(b.id||0,10))); state.routeAgenda=routes; state.routes=routes; if(state.selectedRouteId && state.routes.some(r=>String(r.id)===String(state.selectedRouteId))){ await selectRoute(state.selectedRouteId,false,false); } renderOwnerRoutesSummary(); renderRouteCalendar(); renderRouteList(); renderReports(); }\n"""
